input.newString:
/* status chip — palette-only: surface=tint, border=rule-strong, dot=signal */
.chip{
  display:inline-flex;align-items:center;gap:6px;
  font-size:10px;
  font-weight:700;
  letter-spacing:.04em;
  text-transform:uppercase;
  padding:3px 8px;
  border-radius:999px;
  border:1px solid var(--c-rule-strong);
  color:var(--c-blue-deep);
  background:var(--c-tint-1);
  margin-left:8px;
  vertical-align:2px;
  line-height:1;
}
.chip::before{
  content:"";
  width:6px;height:6px;border-radius:50%;
  background:var(--c-blue);
  flex:none;
}
.chip.ok{color:var(--c-green)}
.chip.ok::before{background:var(--c-green)}
.chip.warn{color:var(--c-blue-deep)}
.chip.warn::before{background:var(--c-gold)}
.chip.alert{color:var(--c-red);border-color:var(--c-red)}
.chip.alert::before{background:var(--c-red)}

